const fieldName = $input.first().json.message.text.body;

// ===============================
// LECTURA SEGURA DEL VALOR
// ===============================
const rawValue = (fieldName ?? '').toString().trim();

// ===============================
// EXTRAER URL SI EXISTE
// ===============================
const urlMatch = rawValue.match(/https?:\/\/[^\s"]+/);
const value = urlMatch ? urlMatch[0] : rawValue;

// ===============================
// VALIDACIONES
// ===============================
const isGoogleMaps =
  value.includes('maps.google.com') ||
  value.includes('google.com/maps') ||
  value.includes('maps.app.goo.gl');

const isLatLon = /^-?\d{1,3}\.\d+\s*,\s*-?\d{1,3}\.\d+$/.test(value);

// ===============================
// RESULTADO
// ===============================
return {
  chatInput: value,
  isGoogleMaps,
  isLatLon,
  isValidLocation: isGoogleMaps || isLatLon
};

const items = $input.all();
const results = [];
for (const item of items) {
  const text = item.json.output;
  const paragraphs = text
    .split(/(?<=[.!?])\s+/)
    .filter(p => p.trim().length > 0);
  for (const p of paragraphs) {
    const cleaned = p
      .replace(/[¿¡]/g, '')
      .replace(/\!/g, '.');
    results.push({ json: { 'output.parrafos': cleaned } });
  }
}
return results;
